import { Request, Response, NextFunction } from 'express';
import { GroupService } from './group.service';
import { CreateGroupDto, UpdateTelegramLinkDto } from './group.dto';
import { AppError } from '../../errors/app.error';
import { StatusCodes } from 'http-status-codes';

export class GroupController {
  private groupService: GroupService;

  constructor(groupService: GroupService) {
    this.groupService = groupService;
  }

  public async createGroup(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const userId = req.user.id;
      const createGroupDto: CreateGroupDto = req.body;
      const group = await this.groupService.createGroup(createGroupDto, userId);
      res.status(StatusCodes.CREATED).json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }

  public async getGroupById(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const groupId = req.params.id;
      const userId = req.user.id;
      const group = await this.groupService.getGroupById(groupId, userId);
      res.status(StatusCodes.OK).json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }

  public async updateTelegramLink(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const groupId = req.params.id;
      const userId = req.user.id;
      const updateTelegramLinkDto: UpdateTelegramLinkDto = req.body;
      const group = await this.groupService.updateTelegramLink(groupId, updateTelegramLinkDto, userId);
      res.status(StatusCodes.OK).json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }
}

import { GroupRepository } from './group.repository';
import { CreateGroupDto, UpdateTelegramLinkDto } from './group.dto';
import { Group } from './group.model';
import { AppError } from '../../errors/app.error';
import { StatusCodes } from 'http-status-codes';

export class GroupService {
  private groupRepository: GroupRepository;

  constructor(groupRepository: GroupRepository) {
    this.groupRepository = groupRepository;
  }

  public async createGroup(createGroupDto: CreateGroupDto, userId: string): Promise<Group> {
    try {
      return await this.groupRepository.createGroup(createGroupDto, userId);
    } catch (error) {
      throw new AppError('SERVICE_CREATE_GROUP_ERROR', 'Failed to create group', StatusCodes.INTERNAL_SERVER_ERROR);
    }
  }

  public async getGroupById(groupId: string, userId: string): Promise<Group> {
    try {
      const group = await this.groupRepository.findGroupById(groupId);
      if (!group) {
        throw new AppError('GROUP_NOT_FOUND', 'Group not found', StatusCodes.NOT_FOUND);
      }
      if (group.adminId.toString() !== userId) {
        throw new AppError('FORBIDDEN', 'Unauthorized access', StatusCodes.FORBIDDEN);
      }
      return group;
    } catch (error) {
      throw error;
    }
  }

  public async updateTelegramLink(groupId: string, updateTelegramLinkDto: UpdateTelegramLinkDto, userId: string): Promise<Group> {
    try {
      const group = await this.groupRepository.findGroupById(groupId);
      if (!group) {
        throw new AppError('GROUP_NOT_FOUND', 'Group not found', StatusCodes.NOT_FOUND);
      }
      if (group.adminId.toString() !== userId) {
        throw new AppError('FORBIDDEN', 'Unauthorized access', StatusCodes.FORBIDDEN);
      }
      return await this.groupRepository.updateTelegramLink(groupId, updateTelegramLinkDto);
    } catch (error) {
      throw error;
    }
  }
}

import { Group, GroupModel } from './group.model';
import { CreateGroupDto, UpdateTelegramLinkDto } from './group.dto';

export class GroupRepository {
  public async createGroup(createGroupDto: CreateGroupDto, userId: string): Promise<Group> {
    const group = new GroupModel({ ...createGroupDto, adminId: userId, createdAt: new Date() });
    return await group.save();
  }

  public async findGroupById(groupId: string): Promise<Group | null> {
    return await GroupModel.findById(groupId).exec();
  }

  public async updateTelegramLink(groupId: string, updateTelegramLinkDto: UpdateTelegramLinkDto): Promise<Group | null> {
    return await GroupModel.findByIdAndUpdate(
      groupId,
      { telegramChatId: updateTelegramLinkDto.telegramChatId },
      { new: true }
    ).exec();
  }
}

import { z } from 'zod';

export const CreateGroupDto = z.object({
  name: z.string().min(1, 'Group name is required'),
  description: z.string().min(1, 'Group description is required'),
});

export const UpdateTelegramLinkDto = z.object({
  telegramChatId: z.string().optional(),
});

export type CreateGroupDto = z.infer<typeof CreateGroupDto>;
export type UpdateTelegramLinkDto = z.infer<typeof UpdateTelegramLinkDto>;

import { Request, Response, NextFunction } from 'express';
import { CreateGroupDto, UpdateTelegramLinkDto } from './group.dto';

export function validateCreateGroup(req: Request, res: Response, next: NextFunction): void {
  try {
    CreateGroupDto.parse(req.body);
    next();
  } catch (error) {
    res.status(400).json({ success: false, message: error.errors });
  }
}

export function validateUpdateTelegramLink(req: Request, res: Response, next: NextFunction): void {
  try {
    UpdateTelegramLinkDto.parse(req.body);
    next();
  } catch (error) {
    res.status(400).json({ success: false, message: error.errors });
  }
}

import { Schema, model, Document } from 'mongoose';

export interface Group extends Document {
  name: string;
  description: string;
  adminId: string;
  members: string[];
  telegramChatId?: string;
  createdAt: Date;
}

const GroupSchema = new Schema<Group>({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: Schema.Types.ObjectId, required: true, ref: 'User' },
  members: [{ type: Schema.Types.ObjectId, ref: 'User' }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now }
});

export const GroupModel = model<Group>('Group', GroupSchema);
